const query =$input.first().json.output;
const lowerQuery = query.toLowerCase();

const forbidden = ["drop", "delete", "update", "insert", "alter", "exec", "truncate", "create", "grant"];

const isUnsafe = forbidden.some(keyword => lowerQuery.includes(keyword));

if (isUnsafe) {
  throw new Error("Rejected unsafe SQL query.");
}

return [{ json: { safeSQL: query } }];
